案例1：循环注册点击事件
/* var lis = document.querySelector(&#39;.nav&#39;).querySelectorAll(&#39;li&#39;) for(var i = 0; i &lt; lis.length; i++) { lis[i].onclick = function() { console.log(i) } } lis[i].onclick 是异步任务，点击了之后才会去执行，但是 for 循环是同步任务，会立即执行。所以 i 永远会是 4。 */ // 利用闭包的方式得到当前 li 的索引 var lis = document.querySelector(&#39;.nav&#39;).querySelectorAll(&#39;li&#39;) for (var i = 0; i &lt; lis.length; i++) { // 利用 for 循环创建了 4 个立即执行函数 (function(j) { lis[j].onclick = function() { console.log(j) } })(i); } 案例2：循环中的 setTimeout()
var lis = document.querySelector(&#39;.nav&#39;).querySelectorAll(&#39;li&#39;) for (var i = 0; i &lt; lis.

交换两个变量的数值 var a = 10, b = 20; a = [b, b = a][0]; console.log(a); // 20 console.log(b); // 10 使用 keys 迭代 获取对象的键名，并组成一个数组。
// 迭代对象 var o = {a: &#39;A&#39;, b: &#39;B&#39;, c: &#39;C&#39;}; console.log(Object.keys(o)); // [&#34;a&#34;, &#34;b&#34;, &#34;c&#34;] // 迭代数组 var a = [&#39;A&#39;, &#39;B&#39;, &#39;C&#39;]; console.log(Object.keys(a)); // [&#34;0&#34;, &#34;1&#34;, &#34;2&#34;] 使用 getOwnPropertyNames 迭代 getOwnPropertyNames 的作用和 keys 相同，不同在于 keys 仅能迭代本地的可枚举的属性，getOwnPropertyNames 可以迭代所有的本地属性。
// 迭代对象 var o = {a: &#39;A&#39;, b: &#39;B&#39;, c: &#39;C&#39;}; console.

@each 指令实例 在 @each 变量的定义，其中包含的每个项目的列表中的值。
@each $var in &lt;list or map&gt; /* $var: 它代表了变量的名称。 @each规则将 $var 每个项目在列表中使用 $var 值输出样式。 &lt;list 或 map&gt;: 这是 SassScript 表达式这将返回一个列表或映射。 */ 示例：
@each $color in red, green, yellow, blue { .p_#{$color} { background-color: #{$color}; } } /* .p_red { background-color: red; } .p_green { background-color: green; } .p_yellow { background-color: yellow; } .p_blue { background-color: blue; } */ @each多重分配 多个值也可以用 @each 指令中使用。如，$var1, $var2,$var3, ... 在 &lt;list&gt;

导入多个scss文件
@import &#34;./scss/lili&#34;, &#34;./scss/haha&#34;; //导入两个文件 extend 函数，不只继承类名选择器的样式，还继承与它相关的样式，包括继承它的父选择器
.test2 { border: 1px #f00; background-color: #fdd; } .test2.test21 { background-image: url(&#34;/image/hacked.png&#34;); } .test2 .test22 { background-image: url(&#34;/image/haha.png&#34;); } html .test2 { width: 100px; } .lili { @extend .test2; border-width: 3px; } /* .test2, .lili { border: 1px #f00; background-color: #fdd; } .test2.test21, .test21.lili { background-image: url(&#34;/image/hacked.png&#34;); } .test2 .test22, .lili .test22 { background-image: url(&#34;/image/haha.png&#34;); } html .test2, html .lili { width: 100px; } .

深拷贝和浅拷贝的区别 浅拷贝（shallow copy）：只复制指向某个对象的指针，而不复制对象本身，新旧对象共享一块内存； 深拷贝（deep copy）：复制并创建一个一摸一样的对象，不共享内存，修改新对象，旧对象保持不变。
浅拷贝的实现 浅拷贝的意思就是只复制引用，而未复制真正的值，有时候我们只是想备份数组，但是只是简单让它赋给一个变量，改变其中一个，另外一个就紧跟着改变，但很多时候这不是我们想要的。
// 对象的浅拷贝举例 var obj = { name:&#39;Hanna Ding&#39;, age: 22 } var obj2 = obj; // 直接复制的是一个对象，只复制了对象的引用，是浅拷贝 obj2[&#39;c&#39;] = 5; console.log(obj); //Object {name: &#34;Hanna Ding&#34;, age: 22, c: 5} console.log(obj2); //Object {name: &#34;Hanna Ding&#34;, age: 22, c: 5} // 数组的浅拷贝举例 var arr = [1, 2, 3, &#39;4&#39;]; var arr2 = arr; arr2[1] = &#34;test&#34;; // 修改数组项 console.log(arr); // [1, &#34;test&#34;, 3, &#34;4&#34;] console.log(arr2); // [1, &#34;test&#34;, 3, &#34;4&#34;] arr[0]=&#34;fisrt&#34;; // 修改数组项 console.
